module priority_encoder (
        input [3:0] in,
        output reg [1:0] invalid_out);

always @(*) begin
    if (in[3])
        invalid_out = 2'b11;
    else if (in[2])
        invalid_out = 2'b10;
    else if (in[1])
        invalid_out = 2'b01;
    else if (in[0])
        invalid_out = 2'b00;
    else
        invalid_out = 2'b00; // Default case, no input is high
end

endmodule
